from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class PdfFolder(SpireObject):
    """
    A folder for the purpose of organizing files into a hierarchical structure.
    The structure is represented by a tree with a single root folder acting as
    the common ancestor for all other folders and files in the collection.
    """

    @property
    def Name(self) -> str:
        """
        (Required; ExtensionLevel3) A file name representing the name of the folder.
        Two sibling folders shall not share the same name following case normalization.
        Note: Descriptions of file name and case normalization follow this table.
        """
        GetDllLibPdf().spr_pdf_PdfFolder_get_Name.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfFolder_get_Name.restype = c_void_p
        ret = PtrToStr(CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_get_Name,self.Ptr))
        return ret

    @dispatch
    def AddFile(self, filePath: str):
        """
        Add a local file into this folder.
        Args: filePath: The local file path.
        """
        GetDllLibPdf().spr_pdf_PdfFolder_AddFile.argtypes = [c_void_p, c_wchar_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_AddFile,self.Ptr, filePath)

    @dispatch
    def AddFile(self, fileName: str, stream: Stream):
        """
        Add a stream into this folder.
        Args: fileName: The file name of the stream.
        Args: stream: The stream.
        """
        intPtrstream: c_void_p = stream.Ptr
        GetDllLibPdf().spr_pdf_PdfFolder_AddFileFS.argtypes = [c_void_p, c_wchar_p, c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_AddFileFS,self.Ptr, fileName, intPtrstream)

    def DeleteFile(self, file: 'PdfAttachment'):
        """
        Delete the file in this folder.
        Args: file: The file.
        """
        intPtrfile: c_void_p = file.Ptr
        GetDllLibPdf().spr_pdf_PdfFolder_DeleteFile.argtypes = [c_void_p, c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_DeleteFile,self.Ptr, intPtrfile)

    def CreateSubfolder(self, folderName: str) -> 'PdfFolder':
        """
        Create a subfolder.
        Args: folderName: The subfolder name.
        Returns: The PdfFolder.
        """
        GetDllLibPdf().spr_pdf_PdfFolder_CreateSubfolder.argtypes = [c_void_p, c_wchar_p]
        GetDllLibPdf().spr_pdf_PdfFolder_CreateSubfolder.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_CreateSubfolder,self.Ptr, folderName)
        ret = None if intPtr == None else PdfFolder(intPtr)
        return ret

    def DeleteSubfolder(self, folderName: str):
        """
        Delete a subfolder.
        Args: folderName: The subfolder name.
        """
        GetDllLibPdf().spr_pdf_PdfFolder_DeleteSubfolder.argtypes = [c_void_p, c_wchar_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_DeleteSubfolder,self.Ptr, folderName)

    def HasSubfolders(self) -> bool:
        """
        Whether has subfolders.
        Returns: True or False
        """
        GetDllLibPdf().spr_pdf_PdfFolder_HasSubfolders.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfFolder_HasSubfolders.restype = c_bool
        ret = CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_HasSubfolders,self.Ptr)
        return ret

    def Clear(self):
        """
        Clear this folder.
        """
        GetDllLibPdf().spr_pdf_PdfFolder_Clear.argtypes = [c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_Clear,self.Ptr)

    def AddExistFolder(self, folderPath: str):
        """
        Add local folder into this folder.
        Args: folderPath: The local folder path.
        """
        GetDllLibPdf().spr_pdf_PdfFolder_AddExistFolder.argtypes = [c_void_p, c_wchar_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFolder_AddExistFolder,self.Ptr, folderPath)